+
+from clickhouse_driver.varint import read_varint, write_varint
+
+
+class VarIntTestCase(TestCase):
+    def test_check_not_negative(self):
+        n = 0x9FFFFFFF
+
+        buf = BytesIO()
+        write_varint(n, buf)
+        val = buf.getvalue()
